input.command:
kubectl patch statefulset mongo-rs -n mongodb --type='json' -p='[
  {
    "op": "replace",
    "path": "/spec/template/spec/containers/0/command",
    "value": [
      "mongod",
      "--replSet", "rs0",
      "--bind_ip_all",
      "--tlsMode", "requireTLS",
      "--tlsCertificateKeyFile", "/etc/tls/server.pem",
      "--tlsCAFile", "/etc/tls/ca.crt"
    ]
  },
  {
    "op": "add",
    "path": "/spec/template/spec/containers/0/volumeMounts/-",
    "value": {
      "name": "tls",
      "mountPath": "/etc/tls",
      "readOnly": true
    }
  },
  {
    "op": "add",
    "path": "/spec/template/spec/volumes",
    "value": [
      {
        "name": "tls",
        "secret": {
          "secretName": "mongo-tls"
        }
      }
    ]
  }
]' 2>&1

